#!/usr/bin/env node

/**
 * Aggregates per-package CHANGELOG.md files (generated by changesets)
 * into the docs changelog page for mkdocs.
 *
 * Reads CHANGELOG.md from each package, merges entries, and writes
 * the result into site/docs/changelog.md.
 */

import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '..');

const packages = [
  { name: '@intrigsoft/pratya-core', dir: 'packages/core' },
  { name: '@intrigsoft/pratya', dir: 'packages/cli' },
  { name: '@intrigsoft/pratya-vitest', dir: 'packages/vitest' },
  { name: '@intrigsoft/pratya-playwright', dir: 'packages/playwright' },
  { name: '@intrigsoft/pratya-jest', dir: 'packages/jest' },
  { name: '@intrigsoft/pratya-mcp-server', dir: 'packages/mcp-server' },
];

let changelog = `# Changelog

All notable changes to Prathya JS packages are documented here.

This changelog is auto-generated from [changesets](https://github.com/changesets/changesets) on each release.

`;

let hasContent = false;

for (const pkg of packages) {
  const changelogPath = join(root, pkg.dir, 'CHANGELOG.md');
  if (!existsSync(changelogPath)) continue;

  const content = readFileSync(changelogPath, 'utf-8').trim();
  if (!content) continue;

  hasContent = true;

  // Strip the leading "# package-name" heading if present
  const lines = content.split('\n');
  const start = lines[0]?.startsWith('# ') ? 1 : 0;
  const body = lines.slice(start).join('\n').trim();

  changelog += `## ${pkg.name}\n\n${body}\n\n`;
}

if (!hasContent) {
  changelog += `_No releases yet. Changelog will appear here after the first release._\n`;
}

const outputPath = join(root, 'site', 'docs', 'changelog.md');
writeFileSync(outputPath, changelog, 'utf-8');

console.log(`Changelog written to ${outputPath}`);
